$REPO = "edburns/Build26-BRK206-your-agent-anywhere-multiclient-multidevice-with-github-copilot-sdk"
$JTBDTASK_BRANCH = "copilot/32-domain-model-database-seeding"
$TIMEOUT = 600
$INTERVAL = 30
$ELAPSED = 0

Write-Host "Waiting for post-CCA workflow runs (e.g., code review)..."

while ($ELAPSED -lt $TIMEOUT) {
    $runs = gh run list -R $REPO --branch "$JTBDTASK_BRANCH" --json databaseId,status,conclusion,name | ConvertFrom-Json

    $inProgress = $runs | Where-Object { $_.status -eq "in_progress" -or $_.status -eq "queued" }
    $actionRequired = $runs | Where-Object { $_.conclusion -eq "action_required" -or $_.status -eq "action_required" }
    $completed = $runs | Where-Object { $_.status -eq "completed" }

    Write-Host "[${ELAPSED}s] In-progress: $($inProgress.Count), Action-required: $($actionRequired.Count), Completed: $($completed.Count), Total: $($runs.Count)"

    if ($actionRequired.Count -gt 0) {
        Write-Host "Found action_required runs - approving..."
        foreach ($run in $actionRequired) {
            Write-Host "  Approving run $($run.databaseId): $($run.name)"
            gh run rerun $run.databaseId -R $REPO
        }
    }

    # If we have more than 1 run (CCA was #1) and nothing is pending
    if ($runs.Count -gt 1 -and $inProgress.Count -eq 0 -and $actionRequired.Count -eq 0) {
        Write-Host "All additional runs complete."
        break
    }

    Start-Sleep -Seconds $INTERVAL
    $ELAPSED += $INTERVAL
}

Write-Host "`nFinal run status:"
gh run list -R $REPO --branch "$JTBDTASK_BRANCH" --json databaseId,status,conclusion,name --jq '.[] | {id: .databaseId, status: .status, conclusion: .conclusion, name: .name}'

